.darma-loader-cssloaders-github-31 {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  border: 4px solid color-mix(in srgb, var(--loader-secondary-color, #bbf7d0) 35%, transparent);
  border-top-color: var(--loader-color, #22c55e);
  border-right-color: var(--loader-color, #22c55e);
  animation: darma-loader-cssloaders-github-31-spin 0.98s cubic-bezier(.55,.15,.45,.85) infinite;
}
.darma-loader-cssloaders-github-31::after {
  content: "";
  display: block;
  width: calc(100% - 16px);
  height: calc(100% - 16px);
  margin: 4px;
  border-radius: 50%;
  border: 3px solid transparent;
  border-bottom-color: var(--loader-secondary-color, #bbf7d0);
  animation: darma-loader-cssloaders-github-31-spin 0.69s linear infinite reverse;
}
@keyframes darma-loader-cssloaders-github-31-spin { to { transform: rotate(360deg); } }

